-- ===================================================================
-- 15. BOM LINES → RAW MATERIAL LINKAGE (update material_id and unit_cost)
-- ===================================================================
UPDATE bom_lines bl SET material_id = rm.id, unit_cost = rm.standard_price
FROM raw_materials rm
WHERE bl.component_name = rm.material_name AND bl.material_id IS NULL;

