-- ===================================================================
-- 19. STATUS TRANSITIONS (Work Order lifecycle)
-- entity_id=30 for work-order
-- to_status_id resolved from entity_statuses by slug lookup
-- ===================================================================
DO $$
DECLARE
  v_entity_id INT := 30;
  v_status_ids RECORD;
BEGIN
  FOR v_status_ids IN
    SELECT slug, id FROM entity_statuses WHERE entity_id = v_entity_id
  LOOP
    NULL;
  END LOOP;

  INSERT INTO status_transitions (entity_id, entity_type, from_status, to_status, to_status_id, label)
  SELECT v_entity_id, 'work-order', t.from_s, t.to_s,
         (SELECT id FROM entity_statuses WHERE entity_id = v_entity_id AND slug = t.to_s LIMIT 1),
         t.lbl
  FROM (VALUES
    ('draft','pending_approval','שלח לאישור'),
    ('pending_approval','approved','אשר'),
    ('approved','in_progress','התחל ייצור'),
    ('in_progress','quality_check','העבר לבקרת איכות'),
    ('quality_check','completed','אשר איכות'),
    ('quality_check','rework','החזר לתיקון'),
    ('rework','in_progress','חזור לייצור'),
    ('pending_approval','rejected','דחה'),
    ('in_progress','on_hold','השהה'),
    ('on_hold','in_progress','חדש ייצור'),
    ('completed','delivered','סמן כנמסר'),
    ('draft','cancelled','בטל')
  ) AS t(from_s, to_s, lbl)
  WHERE NOT EXISTS (
    SELECT 1 FROM status_transitions st
    WHERE st.entity_id = v_entity_id AND st.from_status = t.from_s AND st.to_status = t.to_s
  );
END $$;

