  '<div dir="rtl" style="font-family: Arial, sans-serif; padding: 20px;"><div style="text-align: center; border-bottom: 3px solid #c41e3a; padding-bottom: 15px; margin-bottom: 20px;"><h1 style="color: #c41e3a; margin: 0;">טכנו-קול עוזי - בקרת איכות</h1><h2 style="color: #333;">דוח בדיקה מס'' {{inspection_number}}</h2></div><table style="width: 100%; border-collapse: collapse; margin-bottom: 20px;"><tr><td style="padding: 8px; border: 1px solid #ddd; background: #f5f5f5;"><strong>מוצר:</strong></td><td style="padding: 8px; border: 1px solid #ddd;">{{product_name}}</td><td style="padding: 8px; border: 1px solid #ddd; background: #f5f5f5;"><strong>תוצאה:</strong></td><td style="padding: 8px; border: 1px solid #ddd; font-weight: bold;">{{result}}</td></tr><tr><td style="padding: 8px; border: 1px solid #ddd; background: #f5f5f5;"><strong>בודק:</strong></td><td style="padding: 8px; border: 1px solid #ddd;">{{inspector_name}}</td><td style="padding: 8px; border: 1px solid #ddd; background: #f5f5f5;"><strong>תאריך:</strong></td><td style="padding: 8px; border: 1px solid #ddd;">{{inspection_date}}</td></tr></table><h3 style="color: #c41e3a;">תוצאות בדיקה</h3><p>כמות שנבדקה: {{quantity_inspected}} | עברה: {{quantity_passed}} | נפסלה: {{quantity_rejected}}</p><h3 style="color: #c41e3a;">סטיות</h3><p>{{deviations}}</p><h3 style="color: #c41e3a;">פעולה מתקנת</h3><p>{{corrective_action}}</p></div>',
  '[{"key":"inspection_number","label":"מספר בדיקה"},{"key":"product_name","label":"מוצר"},{"key":"result","label":"תוצאה"},{"key":"inspector_name","label":"בודק"},{"key":"inspection_date","label":"תאריך"},{"key":"quantity_inspected","label":"כמות שנבדקה"},{"key":"quantity_passed","label":"כמות שעברה"},{"key":"quantity_rejected","label":"כמות שנפסלה"},{"key":"deviations","label":"סטיות"},{"key":"corrective_action","label":"פעולה מתקנת"}]'::jsonb,
  '{}'::jsonb,
  '{"size":"A4","orientation":"portrait"}'::jsonb,
  true
)
ON CONFLICT DO NOTHING;

-- ===================================================================
-- 22. BOM HEADER COST RECALCULATION
-- ===================================================================
UPDATE bom_headers bh SET total_material_cost = sub.total_cost
FROM (
  SELECT bl.bom_header_id, SUM(bl.unit_cost * bl.quantity) as total_cost
  FROM bom_lines bl WHERE bl.material_id IS NOT NULL
  GROUP BY bl.bom_header_id
) sub
WHERE bh.id = sub.bom_header_id;
